static inline void check_cuda(cudaError_t e) {
    if (e != cudaSuccess) {
        printf("\nCUDA error: %s\n", cudaGetErrorString(e));
        exit(1);
    }
}

static inline long long get_time_common() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000LL) + tv.tv_usec;
}

static inline double elapsed_time_common(long long start_time, long long end_time) {
    return (double)(end_time - start_time) / (1000.0 * 1000.0);
}

namespace naive_impl {

static long M = INT_MAX;
static int A = 1103515245;
static int C = 12345;
static const int threads_per_block = 128;
static int device_id_inuse = 0;
static int platform_id_inuse = 0;

__global__ void particle_kernel(double * arrayX, double * arrayY, double * CDF, double * u,
                                double * xj, double * yj, int Nparticles) {
    int i = blockDim.x * blockIdx.x + threadIdx.x;
    if (i < Nparticles) {
        int index = -1;
        for (int x = 0; x < Nparticles; x++) {
            if (CDF[x] >= u[i]) {
                index = x;
                break;
            }
        }
        if (index == -1) {
            index = Nparticles - 1;
        }
        xj[i] = arrayX[index];
        yj[i] = arrayY[index];
    }
}

double roundDouble(double value) {
    int newValue = (int)(value);
    if (value - newValue < .5)
        return newValue;
    else
        return newValue++;
}

void setIf(int testValue, int newValue, int * array3D, int * dimX, int * dimY, int * dimZ) {
    for (int x = 0; x < *dimX; x++) {
        for (int y = 0; y < *dimY; y++) {
            for (int z = 0; z < *dimZ; z++) {
                if (array3D[x * *dimY * *dimZ + y * *dimZ + z] == testValue)
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] = newValue;
            }
        }
    }
}

double randu(int * seed, int index) {
    int num = A * seed[index] + C;
    seed[index] = num % M;
    return fabs(seed[index] / ((double) M));
}

double randn(int * seed, int index) {
    double u = randu(seed, index);
    double v = randu(seed, index);
    double cosine = cos(2 * PI * v);
    double rt = -2 * log(u);
    return sqrt(rt) * cosine;
}

void addNoise(int * array3D, int * dimX, int * dimY, int * dimZ, int * seed) {
    for (int x = 0; x < *dimX; x++) {
        for (int y = 0; y < *dimY; y++) {
            for (int z = 0; z < *dimZ; z++) {
                array3D[x * *dimY * *dimZ + y * *dimZ + z] =
                    array3D[x * *dimY * *dimZ + y * *dimZ + z] + (int)(5 * randn(seed, 0));
            }
        }
    }
}

void strelDisk(int * disk, int radius) {
    int diameter = radius * 2 - 1;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            double distance = sqrt(pow((double)(x - radius + 1), 2) +
                                   pow((double)(y - radius + 1), 2));
            if (distance < radius)
                disk[x * diameter + y] = 1;
            else
                disk[x * diameter + y] = 0;
        }
    }
}

void dilate_matrix(int * matrix, int posX, int posY, int posZ,
                   int dimX, int dimY, int dimZ, int error) {
    int startX = posX - error;
    while (startX < 0) startX++;
    int startY = posY - error;
    while (startY < 0) startY++;
    int endX = posX + error;
    while (endX > dimX) endX--;
    int endY = posY + error;
    while (endY > dimY) endY--;

    for (int x = startX; x < endX; x++) {
        for (int y = startY; y < endY; y++) {
            double distance = sqrt(pow((double)(x - posX), 2) +
                                   pow((double)(y - posY), 2));
            if (distance < error)
                matrix[x * dimY * dimZ + y * dimZ + posZ] = 1;
        }
    }
}

void imdilate_disk(int * matrix, int dimX, int dimY, int dimZ, int error, int * newMatrix) {
    for (int z = 0; z < dimZ; z++) {
        for (int x = 0; x < dimX; x++) {
            for (int y = 0; y < dimY; y++) {
                if (matrix[x * dimY * dimZ + y * dimZ + z] == 1) {
                    dilate_matrix(newMatrix, x, y, z, dimX, dimY, dimZ, error);
                }
            }
        }
    }
}

void getneighbors(int * se, int numOnes, double * neighbors, int radius) {
    int neighY = 0;
    int center = radius - 1;
    int diameter = radius * 2 - 1;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            if (se[x * diameter + y]) {
                neighbors[neighY * 2] = (int)(y - center);
                neighbors[neighY * 2 + 1] = (int)(x - center);
                neighY++;
            }
        }
    }
}

void videoSequence(int * I, int IszX, int IszY, int Nfr, int * seed) {
    int max_size = IszX * IszY * Nfr;

    int x0 = (int)roundDouble(IszY / 2.0);
    int y0 = (int)roundDouble(IszX / 2.0);
    I[x0 * IszY * Nfr + y0 * Nfr + 0] = 1;

    for (int k = 1; k < Nfr; k++) {
        int xk = abs(x0 + (k - 1));
        int yk = abs(y0 - 2 * (k - 1));
        int pos = yk * IszY * Nfr + xk * Nfr + k;
        if (pos >= max_size)
            pos = 0;
        I[pos] = 1;
    }

    int * newMatrix = (int *)malloc(sizeof(int) * IszX * IszY * Nfr);
    memset(newMatrix, 0, sizeof(int) * IszX * IszY * Nfr);
    imdilate_disk(I, IszX, IszY, Nfr, 5, newMatrix);

    for (int x = 0; x < IszX; x++) {
        for (int y = 0; y < IszY; y++) {
            for (int k = 0; k < Nfr; k++) {
                I[x * IszY * Nfr + y * Nfr + k] =
                    newMatrix[x * IszY * Nfr + y * Nfr + k];
            }
        }
    }
    free(newMatrix);

    setIf(0, 100, I, &IszX, &IszY, &Nfr);
    setIf(1, 228, I, &IszX, &IszY, &Nfr);
    addNoise(I, &IszX, &IszY, &Nfr, seed);
}

double calcLikelihoodSum(int * I, int * ind, int numOnes) {
    double likelihoodSum = 0.0;
    for (int y = 0; y < numOnes; y++) {
        double a = (double)(I[ind[y]] - 100);
        double b = (double)(I[ind[y]] - 228);
        likelihoodSum += (a * a - b * b) / 50.0;
    }
    return likelihoodSum;
}

int particleFilter(int * I, int IszX, int IszY, int Nfr, int * seed, int Nparticles) {
    int max_size = IszX * IszY * Nfr;
    long long start = get_time_common();

    double xe = roundDouble(IszY / 2.0);
    double ye = roundDouble(IszX / 2.0);

    int radius = 5;
    int diameter = radius * 2 - 1;
    int * disk = (int *)malloc(diameter * diameter * sizeof(int));
    strelDisk(disk, radius);

    int countOnes = 0;
    for (int x = 0; x < diameter; x++) {
        for (int y = 0; y < diameter; y++) {
            if (disk[x * diameter + y] == 1)
                countOnes++;
        }
    }

    double * objxy = (double *)malloc(countOnes * 2 * sizeof(double));
    getneighbors(disk, countOnes, objxy, radius);

    long long get_neighbors = get_time_common();
    printf("TIME TO GET NEIGHBORS TOOK: %f\n", elapsed_time_common(start, get_neighbors));

    double * weights = (double *)malloc(sizeof(double) * Nparticles);
    for (int x = 0; x < Nparticles; x++) {
        weights[x] = 1 / ((double)(Nparticles));
    }

    long long get_weights = get_time_common();
    printf("TIME TO GET WEIGHTSTOOK: %f\n", elapsed_time_common(get_neighbors, get_weights));

    double * likelihood = (double *)malloc(sizeof(double) * Nparticles);
    double * arrayX = (double *)malloc(sizeof(double) * Nparticles);
    double * arrayY = (double *)malloc(sizeof(double) * Nparticles);
    double * xj = (double *)malloc(sizeof(double) * Nparticles);
    double * yj = (double *)malloc(sizeof(double) * Nparticles);
    double * CDF = (double *)malloc(sizeof(double) * Nparticles);
    int * ind = (int *)malloc(sizeof(int) * countOnes);
    double * u = (double *)malloc(sizeof(double) * Nparticles);

    double * arrayX_GPU;
    double * arrayY_GPU;
    double * xj_GPU;
    double * yj_GPU;
    double * CDF_GPU;
    double * u_GPU;

    check_cuda(cudaSetDevice(device_id_inuse));
    check_cuda(cudaMalloc((void **)&arrayX_GPU, sizeof(double) * Nparticles));
    check_cuda(cudaMalloc((void **)&arrayY_GPU, sizeof(double) * Nparticles));
    check_cuda(cudaMalloc((void **)&xj_GPU, sizeof(double) * Nparticles));
    check_cuda(cudaMalloc((void **)&yj_GPU, sizeof(double) * Nparticles));
    check_cuda(cudaMalloc((void **)&CDF_GPU, sizeof(double) * Nparticles));
    check_cuda(cudaMalloc((void **)&u_GPU, sizeof(double) * Nparticles));

    for (int x = 0; x < Nparticles; x++) {
        arrayX[x] = xe;
        arrayY[x] = ye;
    }

    for (int k = 1; k < Nfr; k++) {
        long long set_arrays = get_time_common();

        for (int x = 0; x < Nparticles; x++) {
            arrayX[x] = arrayX[x] + 1.0 + 5.0 * randn(seed, x);
            arrayY[x] = arrayY[x] - 2.0 + 2.0 * randn(seed, x);
        }

        long long error = get_time_common();
        printf("TIME TO SET ERROR TOOK: %f\n", elapsed_time_common(set_arrays, error));

        for (int x = 0; x < Nparticles; x++) {
            for (int y = 0; y < countOnes; y++) {
                int indX = (int)roundDouble(arrayX[x]) + (int)objxy[y * 2 + 1];
                int indY = (int)roundDouble(arrayY[x]) + (int)objxy[y * 2];
                ind[y] = abs(indX * IszY * Nfr + indY * Nfr + k);
                if (ind[y] >= max_size)
                    ind[y] = 0;
            }
            likelihood[x] = calcLikelihoodSum(I, ind, countOnes);
            likelihood[x] = likelihood[x] / countOnes;
        }

        long long likelihood_time = get_time_common();
        printf("TIME TO GET LIKELIHOODS TOOK: %f\n", elapsed_time_common(error, likelihood_time));

        for (int x = 0; x < Nparticles; x++) {
            weights[x] = weights[x] * exp(likelihood[x]);
        }

        long long exponential = get_time_common();
        printf("TIME TO GET EXP TOOK: %f\n", elapsed_time_common(likelihood_time, exponential));

        double sumWeights = 0;
        for (int x = 0; x < Nparticles; x++) {
            sumWeights += weights[x];
        }

        long long sum_time = get_time_common();
        printf("TIME TO SUM WEIGHTS TOOK: %f\n", elapsed_time_common(exponential, sum_time));

        for (int x = 0; x < Nparticles; x++) {
            weights[x] = weights[x] / sumWeights;
        }

        long long normalize = get_time_common();
        printf("TIME TO NORMALIZE WEIGHTS TOOK: %f\n", elapsed_time_common(sum_time, normalize));

        xe = 0;
        ye = 0;
        for (int x = 0; x < Nparticles; x++) {
            xe += arrayX[x] * weights[x];
            ye += arrayY[x] * weights[x];
        }

        long long move_time = get_time_common();
        printf("TIME TO MOVE OBJECT TOOK: %f\n", elapsed_time_common(normalize, move_time));
        printf("XE: %lf\n", xe);
        printf("YE: %lf\n", ye);
        double distance = sqrt(pow((double)(xe - (int)roundDouble(IszY / 2.0)), 2) +
                               pow((double)(ye - (int)roundDouble(IszX / 2.0)), 2));
        printf("%lf\n", distance);

        CDF[0] = weights[0];
        for (int x = 1; x < Nparticles; x++) {
            CDF[x] = weights[x] + CDF[x - 1];
        }

        long long cum_sum = get_time_common();
        printf("TIME TO CALC CUM SUM TOOK: %f\n", elapsed_time_common(move_time, cum_sum));

        double u1 = (1 / ((double)(Nparticles))) * randu(seed, 0);
        for (int x = 0; x < Nparticles; x++) {
            u[x] = u1 + x / ((double)(Nparticles));
        }

        long long u_time = get_time_common();
        printf("TIME TO CALC U TOOK: %f\n", elapsed_time_common(cum_sum, u_time));

        long long start_copy = get_time_common();
        check_cuda(cudaMemcpy(arrayX_GPU, arrayX, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));
        check_cuda(cudaMemcpy(arrayY_GPU, arrayY, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));
        check_cuda(cudaMemcpy(CDF_GPU, CDF, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));
        check_cuda(cudaMemcpy(u_GPU, u, sizeof(double) * Nparticles, cudaMemcpyHostToDevice));
        long long end_copy = get_time_common();

        int num_blocks = (int)ceil((double)Nparticles / (double)threads_per_block);
        particle_kernel<<<num_blocks, threads_per_block>>>(arrayX_GPU, arrayY_GPU, CDF_GPU, u_GPU, xj_GPU, yj_GPU, Nparticles);
        check_cuda(cudaGetLastError());
        check_cuda(cudaDeviceSynchronize());
        long long start_copy_back = get_time_common();

        check_cuda(cudaMemcpy(yj, yj_GPU, sizeof(double) * Nparticles, cudaMemcpyDeviceToHost));
        check_cuda(cudaMemcpy(xj, xj_GPU, sizeof(double) * Nparticles, cudaMemcpyDeviceToHost));

        long long end_copy_back = get_time_common();
        printf("SENDING TO GPU TOOK: %lf\n", elapsed_time_common(start_copy, end_copy));
        printf("OPEN_CL EXEC TOOK: %lf\n", elapsed_time_common(end_copy, start_copy_back));
        printf("SENDING BACK FROM GPU TOOK: %lf\n", elapsed_time_common(start_copy_back, end_copy_back));

        long long xyj_time = get_time_common();
        printf("TIME TO CALC NEW ARRAY X AND Y TOOK: %f\n", elapsed_time_common(u_time, xyj_time));

        for (int x = 0; x < Nparticles; x++) {
            arrayX[x] = xj[x];
            arrayY[x] = yj[x];
            weights[x] = 1 / ((double)(Nparticles));
        }

        long long reset = get_time_common();
        printf("TIME TO RESET WEIGHTS TOOK: %f\n", elapsed_time_common(xyj_time, reset));
    }

    cudaFree(u_GPU);
    cudaFree(CDF_GPU);
    cudaFree(yj_GPU);
    cudaFree(xj_GPU);
    cudaFree(arrayY_GPU);
    cudaFree(arrayX_GPU);

    free(disk);
    free(objxy);
    free(weights);
    free(likelihood);
    free(xj);
    free(yj);
    free(arrayX);
    free(arrayY);
    free(CDF);
    free(u);
    free(ind);

    return 0;
}

int main_impl(int argc, char * argv[]) {
    const char* usage = "naive.out -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles> [-p platform] [-d device]";

    if (argc != 9) {
        printf("%s\n", usage);
        return 0;
    }

    if (strcmp(argv[1], "-x") || strcmp(argv[3], "-y") || strcmp(argv[5], "-z") || strcmp(argv[7], "-np")) {
        printf("%s\n", usage);
        return 0;
    }

    int IszX, IszY, Nfr, Nparticles;

    if (sscanf(argv[2], "%d", &IszX) == EOF) {
        printf("ERROR: dimX input is incorrect");
        return 0;
    }
    if (IszX <= 0) {
        printf("dimX must be > 0\n");
        return 0;
    }

    if (sscanf(argv[4], "%d", &IszY) == EOF) {
        printf("ERROR: dimY input is incorrect");
        return 0;
    }
    if (IszY <= 0) {
        printf("dimY must be > 0\n");
        return 0;
    }

    if (sscanf(argv[6], "%d", &Nfr) == EOF) {
        printf("ERROR: Number of frames input is incorrect");
        return 0;
    }
    if (Nfr <= 0) {
        printf("number of frames must be > 0\n");
        return 0;
    }

    if (sscanf(argv[8], "%d", &Nparticles) == EOF) {
        printf("ERROR: Number of particles input is incorrect");
        return 0;
    }
    if (Nparticles <= 0) {
        printf("Number of particles must be > 0\n");
        return 0;
    }

    int * seed = (int *)malloc(sizeof(int) * Nparticles);
    for (int i = 0; i < Nparticles; i++)
        seed[i] = time(0) * i;

    int * I = (int *)malloc(sizeof(int) * IszX * IszY * Nfr);
    memset(I, 0, sizeof(int) * IszX * IszY * Nfr);

    long long start = get_time_common();
    videoSequence(I, IszX, IszY, Nfr, seed);
    long long endVideoSequence = get_time_common();
    printf("VIDEO SEQUENCE TOOK %f\n", (float)elapsed_time_common(start, endVideoSequence));

    particleFilter(I, IszX, IszY, Nfr, seed, Nparticles);
    long long endParticleFilter = get_time_common();
    printf("PARTICLE FILTER TOOK %f\n", (float)elapsed_time_common(endVideoSequence, endParticleFilter));
    printf("ENTIRE PROGRAM TOOK %f\n", (float)elapsed_time_common(start, endParticleFilter));

    free(seed);
    free(I);
    return 0;
}

