int main_impl(int argc, char * argv[]) {
    const char* usage = "double.out -x <dimX> -y <dimY> -z <Nfr> -np <Nparticles> [-p platform] [-d device]";

    if (argc < 9) {
        printf("%s\n", usage);
        return 0;
    }

    if (strcmp(argv[1], "-x") || strcmp(argv[3], "-y") || strcmp(argv[5], "-z") || strcmp(argv[7], "-np")) {
        printf("%s\n", usage);
        return 0;
    }

    int IszX, IszY, Nfr, Nparticles;

    if (sscanf(argv[2], "%d", &IszX) == EOF) {
        printf("ERROR: dimX input is incorrect");
        return 0;
    }
    if (IszX <= 0) {
        printf("dimX must be > 0\n");
        return 0;
    }

    if (sscanf(argv[4], "%d", &IszY) == EOF) {
        printf("ERROR: dimY input is incorrect");
        return 0;
    }
    if (IszY <= 0) {
        printf("dimY must be > 0\n");
        return 0;
    }

    if (sscanf(argv[6], "%d", &Nfr) == EOF) {
        printf("ERROR: Number of frames input is incorrect");
        return 0;
    }
    if (Nfr <= 0) {
        printf("number of frames must be > 0\n");
        return 0;
    }

    if (sscanf(argv[8], "%d", &Nparticles) == EOF) {
        printf("ERROR: Number of particles input is incorrect");
        return 0;
    }
    if (Nparticles <= 0) {
        printf("Number of particles must be > 0\n");
        return 0;
    }

    for (int i = 9; i < argc; ++i) {
        switch (argv[i][1]) {
            case 'p':
                if (++i < argc)
                    sscanf(argv[i], "%d", &platform_id_inuse);
                break;
            case 'd':
                if (++i < argc)
                    sscanf(argv[i], "%d", &device_id_inuse);
                break;
            default:
                ;
        }
    }

    int * seed = (int *)calloc(Nparticles, sizeof(int));
    for (int i = 0; i < Nparticles; i++)
        seed[i] = i + 1;

    unsigned char * I = (unsigned char *)calloc(IszX * IszY * Nfr, sizeof(unsigned char));

    long long start = get_time_common();
    opt_common::videoSequence<double>(I, IszX, IszY, Nfr, seed);
    long long endVideoSequence = get_time_common();
    printf("VIDEO SEQUENCE TOOK %f\n", elapsed_time_common(start, endVideoSequence));

    opt_common::particleFilter<double, false>(I, IszX, IszY, Nfr, seed, Nparticles,
                                              threads_per_block, device_id_inuse, platform_id_inuse);
    long long endParticleFilter = get_time_common();
    printf("PARTICLE FILTER TOOK %f\n", elapsed_time_common(endVideoSequence, endParticleFilter));
    printf("ENTIRE PROGRAM TOOK %f\n", elapsed_time_common(start, endParticleFilter));

    free(seed);
    free(I);
    return 0;
}

